function sumOfPoints(s, answers) {
    let total_points = 0;
    let result = 0, term = 1;
    let sign = '+';

    for (let i = 0; i < s.length; i++) {
        if (s[i].charCodeAt(0) >= '0'.charCodeAt(0) && s[i].charCodeAt(0) <= '9'.charCodeAt(0)) {
            let number = s[i].charCodeAt(0) - '0'.charCodeAt(0);
            if (sign === '+') {
                result += term;
                term = number;
            } else if (sign === '*') {
                term *= number;
            }
        } else {
           sign = s[i];
        }
    }

    result += term;

    for (let ans of answers) {
        total_points += (ans === result) ? 1 : 0;
    }

    return total_points;
}
