public int sumOfPoints(String s, int[] answers) {
    int total_points = 0;
    int result = 0, term = 1;
    char sign = '+';

    for (int i = 0; i < s.length(); i++) {
        if (Character.isDigit(s.charAt(i))) {
            int number = s.charAt(i) - '0';
            if (sign == '+') {
                result += term;
                term = number;
            } else if (sign == '*') {
                term *= number;
            }
        } else {
            sign = s.charAt(i);
        }
    }
    result += term;

    for (int ans : answers) {
        total_points += (ans == result) ? 1 : 0;
    }

    return total_points;
}
```


